 71→impl ColorMode {
 72→    fn use_color(self) -> bool {
 73→        match self {
 74→            ColorMode::Always => true,
 75→            ColorMode::Never => false,
 76→            ColorMode::Auto => {
 77→                std::io::stdout().is_terminal() && std::env::var_os("NO_COLOR").is_none()
 78→            }
 79→        }
 80→    }
