 83→impl Cli {
 84→    /// Resolve the effective log level from --log-level, -v, and -q flags.
 85→    fn effective_log_level(&self) -> LogLevel {
 86→        if self.quiet {
 87→            return LogLevel::Warn;
 88→        }
 89→        match self.verbose {
 90→            0 => self.log_level,
 91→            1 => LogLevel::Debug,
 92→            _ => LogLevel::Trace,
 93→        }
 94→    }
 95→
 96→}
